#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10,M=2e5+10,INF=(1LL<<31)-1;

int n,m,s;
int head[N],ver[M],sum[M],nxt[M],edge[M],tot;
long long ans,val[N],f[N];
int dfn[N],low[N],num,stk[N],top,cnt,c[N],d[N];
bool ins[N];

struct Edge{
    int to,val;
};

vector<Edge> g[N];

int cal(int w,double r){
    long long res=0;
    int tmp=r*10;
    while(w){
        res+=w;
        w=1LL*w*tmp/10;
        //if(res>INF)
        //    return INF;
    }
    return res;
}

void add(int u,int v,int w,double r){
    ver[++tot]=v,edge[tot]=w,sum[tot]=cal(w,r),nxt[tot]=head[u],head[u]=tot;
}

void tarjan(int x){
    dfn[x]=low[x]=++num;
    stk[++top]=x,ins[x]=1;
    for(int i=head[x],y;i;i=nxt[i])
        if(!dfn[y=ver[i]]){
            tarjan(y);
            low[x]=min(low[x],low[y]);
        }else if(ins[y])
            low[x]=min(low[x],dfn[y]);
    if(dfn[x]==low[x]){
        int z;
        cnt++;
        do{
            z=stk[top--],ins[z]=0,c[z]=cnt;
        }while(z!=x);
    }
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++){
        int u,v,w;
        double r;
        scanf("%d%d%d%lf",&u,&v,&w,&r);
        add(u,v,w,r);
    }
    scanf("%d",&s);
    tarjan(s);
    for(int i=1;i<=n;i++){
        if(!c[i])
            continue;
        for(int j=head[i];j;j=nxt[j]){
            if(c[ver[j]]==c[i]){
                val[c[ver[j]]]+=sum[j];
            }else
                d[c[ver[j]]]++,g[c[i]].push_back({c[ver[j]],edge[j]});
        }
    }
    queue<int> q;
    q.push(c[s]);
    f[c[s]]=val[c[s]];
    while(q.size()){
        int x=q.front();
        q.pop();
        ans=max(ans,f[x]);
        for(Edge y:g[x]){
            d[y.to]--,f[y.to]=max(f[y.to],f[x]+val[y.to]+y.val);
            if(!d[y.to])
                q.push(y.to);
        }
    }
    printf("%lld",ans);
    return 0;
}
